function ABody({sections}) {
  return (
    <div style={{display:"flex",flexDirection:"column",gap:14}}>
      {sections.map((s,i)=>{
        if(s.type==="heading") return <div key={i} style={{fontFamily:"Syne,sans-serif",fontWeight:700,fontSize:15,color:C.text,marginTop:6}}>{s.content}</div>;
        if(s.type==="text"||s.type==="story") return <div key={i} style={{fontSize:13,color:C.muted,lineHeight:1.8}}>{s.content}</div>;
        if(s.type==="bullets") return (
          <div key={i} style={{display:"flex",flexDirection:"column",gap:8}}>
            {s.items.map((item,j)=>(
              <div key={j} style={{display:"flex",gap:10,alignItems:"flex-start",background:"rgba(43,127,255,0.06)",borderRadius:10,padding:"9px 12px"}}>
                <span style={{color:C.accent,fontSize:13,flexShrink:0}}>→</span>
                <span style={{fontSize:13,color:C.text,lineHeight:1.6,opacity:0.8}}>{item}</span>
              </div>
            ))}
          </div>
        );
        if(s.type==="steps") return (
          <div key={i} style={{display:"flex",flexDirection:"column",gap:10}}>
            {s.items.map((item,j)=>(
              <div key={j} style={{display:"flex",gap:10,alignItems:"flex-start"}}>
                <div style={{minWidth:22,height:22,borderRadius:"50%",background:C.accent,color:"#fff",display:"flex",alignItems:"center",justifyContent:"center",fontSize:11,fontWeight:700,flexShrink:0}}>{j+1}</div>
                <span style={{fontSize:13,color:C.text,lineHeight:1.6,opacity:0.8}}>{item}</span>
              </div>
            ))}
          </div>
        );
        if(s.type==="quote") return (
          <div key={i} style={{background:C.accentGlow,borderLeft:"3px solid "+C.accent,borderRadius:"0 10px 10px 0",padding:"12px 14px"}}>
            <div style={{fontFamily:"Syne,sans-serif",fontStyle:"italic",fontSize:14,color:C.accentL}}>{s.content}</div>
          </div>
        );
        return null;
      })}
    </div>
  );
}

function Gallery({images}) {
  const [idx,setIdx] = useState(0);
  if(!images||images.length===0) return null;
  const img = images[idx];
  const isReal = !!(img.src && img.src.startsWith("data:image/jpeg"));
  return (
    <div style={{marginBottom:14}}>
      <div style={{position:"relative",height:200,borderRadius:16,overflow:"hidden",background:"linear-gradient(135deg,#0A1828,#0D2040)",marginBottom:10}}>
        {isReal
          ? <img src={img.src} alt={img.label} style={{width:"100%",height:"100%",objectFit:"cover"}}/>
          : <div style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",height:"100%",gap:10}}>
              <span style={{fontSize:40}}>{img.icon}</span>
              <span style={{fontFamily:"Syne,sans-serif",fontWeight:700,fontSize:13,color:"rgba(255,255,255,0.6)"}}>{img.label}</span>
            </div>
        }
        <div style={{position:"absolute",bottom:10,left:10,background:"rgba(7,16,28,0.8)",borderRadius:20,padding:"4px 12px",fontSize:12,fontFamily:"Syne,sans-serif",fontWeight:600,color:C.text}}>
          {img.icon} {img.label}
        </div>
        {images.length>1 && <>
          <button onClick={()=>setIdx((idx-1+images.length)%images.length)} style={{position:"absolute",left:8,top:"50%",transform:"translateY(-50%)",background:"rgba(7,16,28,0.7)",border:"none",color:"#fff",borderRadius:"50%",width:30,height:30,cursor:"pointer",fontSize:16}}>‹</button>
          <button onClick={()=>setIdx((idx+1)%images.length)} style={{position:"absolute",right:8,top:"50%",transform:"translateY(-50%)",background:"rgba(7,16,28,0.7)",border:"none",color:"#fff",borderRadius:"50%",width:30,height:30,cursor:"pointer",fontSize:16}}>›</button>
        </>}
      </div>
      <div style={{display:"flex",gap:6,overflowX:"auto",paddingBottom:4}}>
        {images.map((im,i)=>(
          <div key={i} onClick={()=>setIdx(i)} style={{flexShrink:0,width:52,height:42,borderRadius:9,overflow:"hidden",cursor:"pointer",border:"2px solid "+(i===idx?C.accent:"transparent"),background:"#0A1828",display:"flex",alignItems:"center",justifyContent:"center",fontSize:16}}>
            {im.src&&im.src.startsWith("data:image/jpeg")
              ? <img src={im.src} alt={im.label} style={{width:"100%",height:"100%",objectFit:"cover"}}/>
              : <span>{im.icon}</span>
            }
          </div>
        ))}
      </div>
    </div>
  );
}

function AnimatedBg() {
  const ref = React.useRef(null);
  React.useEffect(()=>{
    const canvas = ref.current;
    if(!canvas) return;
    const ctx = canvas.getContext("2d");
    let raf, t=0;
    const pts = Array.from({length:50},()=>({x:Math.random(),y:Math.random(),r:Math.random()*1.2+0.4,speed:Math.random()*0.00015+0.00005,drift:(Math.random()-0.5)*0.0001,op:Math.random()*0.5+0.1}));
    const resize=()=>{canvas.width=canvas.offsetWidth*window.devicePixelRatio;canvas.height=canvas.offsetHeight*window.devicePixelRatio;ctx.scale(window.devicePixelRatio,window.devicePixelRatio);};
    resize();
    window.addEventListener("resize",resize);
    const draw=()=>{
      t+=0.005;
      const W=canvas.offsetWidth,H=canvas.offsetHeight;
      ctx.clearRect(0,0,W,H);
      const bg=ctx.createLinearGradient(0,0,W,H);
      bg.addColorStop(0,"#040D18");bg.addColorStop(0.5,"#071528");bg.addColorStop(1,"#04101E");
      ctx.fillStyle=bg;ctx.fillRect(0,0,W,H);
      [{x:0.3+Math.sin(t*0.4)*0.08,y:0.4+Math.cos(t*0.3)*0.06,r:0.45,c:"rgba(43,127,255,0.07)"},{x:0.7+Math.cos(t*0.35)*0.07,y:0.5+Math.sin(t*0.5)*0.08,r:0.38,c:"rgba(100,60,255,0.08)"}].forEach(b=>{
        const g=ctx.createRadialGradient(b.x*W,b.y*H,0,b.x*W,b.y*H,b.r*Math.max(W,H));
        g.addColorStop(0,b.c);g.addColorStop(1,"rgba(0,0,0,0)");
        ctx.fillStyle=g;ctx.fillRect(0,0,W,H);
      });
      ctx.strokeStyle="rgba(43,127,255,0.04)";ctx.lineWidth=0.5;
      const gs=40,ox=(t*8)%gs,oy=(t*5)%gs;
      for(let x=-gs+ox;x<W+gs;x+=gs){ctx.beginPath();ctx.moveTo(x,0);ctx.lineTo(x,H);ctx.stroke();}
      for(let y=-gs+oy;y<H+gs;y+=gs){ctx.beginPath();ctx.moveTo(0,y);ctx.lineTo(W,y);ctx.stroke();}
      pts.forEach(p=>{
        p.y-=p.speed;p.x+=p.drift;
        if(p.y<0){p.y=1;p.x=Math.random();}
        if(p.x<0||p.x>1)p.x=Math.random();
        const pulse=0.7+Math.sin(t*3+p.x*10)*0.3;
        ctx.beginPath();ctx.arc(p.x*W,p.y*H,p.r,0,Math.PI*2);
        ctx.fillStyle="rgba(180,210,255,"+(p.op*pulse)+")";ctx.fill();
      });
      raf=requestAnimationFrame(draw);
    };
    draw();
    return()=>{cancelAnimationFrame(raf);window.removeEventListener("resize",resize);};
  },[]);
  return <canvas ref={ref} style={{position:"absolute",inset:0,width:"100%",height:"100%",zIndex:0}}/>;
}

